def classificar_status(codigo: int) -> str:
    if 100 <= codigo < 200:
        return "informational"
    elif 200 <= codigo < 300:
        return "success"
    elif 300 <= codigo < 400:
        return "redirection"
    elif 400 <= codigo < 500:
        return "client_error"
    elif 500 <= codigo < 600:
        return "server_error"
    return "unknown"
